VALUES ('fe51a715-75d5-44f6-8c97-1194a7d655e9', 'Which choice completes the text with the most logical transition?', 'The first trial failed to detect an effect. ______ the second trial, with more participants, showed a clear pattern.', NULL, '[{"id":"A","text":"Nevertheless","is_correct":true,"explanation":"Signals contrast between the two trials."},{"id":"B","text":"Thus","is_correct":false,"explanation":"Implies direct consequence; the contrast fits better."},{"id":"C","text":"Meanwhile","is_correct":false,"explanation":"Suggests simultaneity, which is not stated."},{"id":"D","text":"In contrast","is_correct":false,"explanation":"Would introduce an example, not a contrasting result."}]'::jsonb, 'A', 'A contrast transition (Nevertheless) links a failed trial to a later successful one.', NULL, 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_bulk_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
